import { useState } from "react";
import { useSelector, useDispatch } from "react-redux";
import { useNavigate } from "react-router-dom";
import { toast } from "react-toastify";
import { addNotification } from "../notificationReducer";

function AddCourse() {
  const [name, setName] = useState("");
  const [file, setFile] = useState(null);
  const user = useSelector((state) => state.auth.user);
  const dispatch = useDispatch();
  const navigate = useNavigate();

  async function handleSubmit(e) {
    e.preventDefault();
    let filePath = null;

    if (file) {
      const allowedTypes = ['image/jpeg', 'image/png', 'application/pdf'];
      const maxSize = 5 * 1024 * 1024;

      if (!allowedTypes.includes(file.type)) {
        toast.error("Допустимы только изображения (JPEG, PNG) или PDF-файлы");
        return;
      }

      if (file.size > maxSize) {
        toast.error("Файл слишком большой. Максимальный размер: 5 МБ");
        return;
      }

      const formData = new FormData();
      formData.append("file", file);
      try {
        const response = await fetch("http://localhost:3002/upload", {
          method: "POST",
          body: formData,
        });
        const data = await response.json();
        if (response.ok) {
          filePath = data.filePath;
        } else {
          toast.error("Не удалось загрузить файл");
          return;
        }
      } catch (error) {
        toast.error("Сетевая ошибка при загрузке файла");
        return;
      }
    }

    const newCourse = { name, teacherId: user.id };
    try {
      const response = await fetch("http://localhost:3001/courses", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(newCourse),
      });

      if (response.ok) {
        const course = await response.json();
        if (filePath) {
          await fetch("http://localhost:3001/files", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({
              courseId: course.id,
              filePath,
              fileName: file.name,
            }),
          });
        }
        dispatch(
          addNotification({
            id: Date.now(),
            userId: user.id,
            message: `Курс ${name} добавлен!`,
            createdAt: new Date().toISOString(),
          })
        );
        await fetch("http://localhost:3001/notifications", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            userId: user.id,
            message: `Курс ${name} добавлен!`,
            createdAt: new Date().toISOString(),
          }),
        });
        toast.success("Курс успешно добавлен!");
        navigate("/courses");
      } else {
        toast.error("Не удалось добавить курс");
      }
    } catch (error) {
      toast.error("Сетевая ошибка при добавлении курса");
    }
  }

  if (user?.role !== "teacher") {
    return <div className="container mt-5"><h1>Доступ запрещен</h1></div>;
  }

  return (
    <div className="container mt-5">
      <div className="row justify-content-center">
        <div className="col-md-6">
          <div className="card">
            <div className="card-body">
              <h2 className="card-title text-center mb-4">Добавить курс</h2>
              <form onSubmit={handleSubmit}>
                <div className="mb-3">
                  <label htmlFor="name" className="form-label">Название курса</label>
                  <input
                    type="text"
                    id="name"
                    className="form-control"
                    value={name}
                    onChange={(e) => setName(e.target.value)}
                    required
                  />
                </div>
                <div className="mb-3">
                  <label htmlFor="file" className="form-label">Прикрепить файл (опционально, только JPEG, PNG, PDF, до 5 МБ)</label>
                  <input
                    type="file"
                    id="file"
                    className="form-control"
                    onChange={(e) => setFile(e.target.files[0])}
                  />
                </div>
                <button type="submit" className="btn btn-primary w-100">
                  Добавить
                </button>
              </form>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

export default AddCourse;
